import pinecone
from pinecone import Pinecone, ServerlessSpec

pc = Pinecone(api_key='YOUR_API_KEY')
index = pc.Index('articles')

# First write -- creates the record
index.upsert(vectors=[
    {'id': 'doc-42', 'values': [0.1, 0.4, ...], 'metadata': {'title': 'HNSW intro', 'version': 1}},
])

# Second write -- replaces the record (same id)
index.upsert(vectors=[
    {'id': 'doc-42', 'values': [0.2, 0.5, ...], 'metadata': {'title': 'HNSW intro', 'version': 2}},
])

# Batch upsert -- recommended size: 100-1,000 per call
